  interface Worksheet {
    dataValidations: {
      add(
        range: string,
        options: {
          type: string;
          allowBlank: boolean;
          showErrorMessage: boolean;
          formulae: string[];
          error: string;
        },
      ): void;
    };
  }
}

@Injectable()
